const event = $input.first().json.events?.[0] || $input.first().json.body?.events?.[0];
const messageText = (event?.message?.text || '').trim();
const replyToken = event?.replyToken || '';

// 格式：發 YC1835328（「發」和編號間空白可省略，全形/半形空白都接受）
const m = messageText.match(/^發[\s\u3000]*([A-Za-z]{2}\d{4,})/);
if (!m) {
  return [{ json: {
    _isError: true,
    replyToken,
    replyText: `❌ 指令格式錯誤\n\n正確格式：發 YC編號\n例：發 YC1835328\n\n收到：「${messageText}」`
  }}];
}
return [{ json: { _isError: false, caseId: m[1].toUpperCase(), replyToken } }];

const cmd = $('解析 LINE 指令').first().json;
const page = ($json.results || [])[0];
if (!page) {
  return [{ json: {
    _isError: true,
    replyToken: cmd.replyToken,
    replyText: `❌ Notion 找不到 ${cmd.caseId}\n\n請先用「建檔 <永慶網址>」把物件建檔進來再發`
  }}];
}

const props = page.properties || {};
const rt = k => (props[k]?.rich_text || []).map(t => t.plain_text || '').join('');
const tt = k => (props[k]?.title?.[0]?.plain_text) || '';
const sel = k => props[k]?.select?.name || '';
const num = k => props[k]?.number ?? null;
const chk = k => !!props[k]?.checkbox;
const url = k => props[k]?.url || '';

const sourceUrl = url('來源連結');
if (!sourceUrl) {
  return [{ json: {
    _isError: true,
    replyToken: cmd.replyToken,
    replyText: `❌ ${cmd.caseId} 的 Notion「來源連結」是空的，抓不到照片\n\n請先補上永慶網址再發`
  }}];
}

return [{ json: {
  _isError: false,
  notionPageId: page.id,
  existingVersion: num('文案版本') || 0,
  粉專文案: rt('粉專文案'),
  社團文案: rt('社團文案'),
  來源連結: sourceUrl,
  案名: tt('案名'),
  社區名稱: rt('社區名稱'),
  地址: rt('地址'),
  建物類型: sel('建物類型'),
  格局: rt('格局'),
  樓層: rt('樓層'),
  屋齡: num('屋齡'),
  總價: rt('總價'),
  單價: rt('單價'),
  建物坪數: num('建物坪數'),
  主建物坪數: num('主建物坪數'),
  公設坪數: num('公設坪數'),
  附屬建物: rt('附屬建物'),
  土地坪數: num('土地坪數'),
  有無車位: chk('有無車位'),
  車位類型: sel('車位類型'),
  特色說明: rt('特色說明'),
  replyToken: cmd.replyToken,
  caseId: cmd.caseId
}}];

