const response = $input.first().json;
const aiText = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
let jsonText = aiText.trim().replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
let parsed;
try { parsed = JSON.parse(jsonText); }
catch (e) { throw new Error('AI 文案 JSON 解析失敗: ' + e.message + ' 原始: ' + aiText.substring(0, 300)); }
if (!parsed['粉專文案'] || !parsed['社團文案']) {
  throw new Error('AI 回傳缺「粉專文案」或「社團文案」: ' + jsonText.substring(0, 300));
}
const src = $('取出物件資料').first().json;
return [{ json: { ...src, 粉專文案: parsed['粉專文案'], 社團文案: parsed['社團文案'], generated: true, newVersion: (src.existingVersion || 0) + 1 } }];

// 網頁抓失敗（onError 續走）→ photoUrls 為空 → 走純文字發文
let src;
try { src = $('解析文案輸出').first().json; } catch (e) { src = null; }
if (!src) src = $('取出物件資料').first().json;

const resp = $input.first().json || {};
let html = resp.data || resp.body || '';
if (typeof html !== 'string') html = '';

const urls = [];
const push = u => {
  if (!u) return;
  u = u.replace(/&amp;/g, '&').trim();
  if (!/^https?:\/\//.test(u)) return;
  const isImg = /\.(jpe?g|png|webp)(\?|$)/i.test(u);
  const isYc = /yungching/i.test(u);
  if (!isImg && !isYc) return;
  if (/logo|icon|sprite|avatar|banner|qrcode/i.test(u)) return;
  if (!urls.includes(u)) urls.push(u);
};

const og = html.match(/<meta[^>]+property=["']og:image["'][^>]*content=["']([^"']+)["']/i)
        || html.match(/<meta[^>]+content=["']([^"']+)["'][^>]*property=["']og:image["']/i);
if (og) push(og[1]);

let m;
const imgRe = /<img[^>]+src=["']([^"']+)["']/gi;
while ((m = imgRe.exec(html)) !== null) push(m[1]);
const lazyRe = /data-src=["']([^"']+)["']/gi;
while ((m = lazyRe.exec(html)) !== null) push(m[1]);

return [{ json: { ...src, photoUrls: urls.slice(0, 6) } }];

// 個別照片上傳失敗會被濾掉（onError 續走）；全滅就變純文字發文
const src = $('抽圖片URL').first().json;
const ids = $input.all().map(i => i.json.id).filter(Boolean);
const fbBody = { message: src['粉專文案'] };
if (ids.length > 0) fbBody.attached_media = ids.map(id => ({ media_fbid: id }));
return [{ json: { fbBody, uploadedPhotos: ids.length } }];

const post = $input.first().json;
if (!post.id) {
  throw new Error('FB 發文沒回傳 post id: ' + JSON.stringify(post).substring(0, 300));
}
const permalink = 'https://www.facebook.com/' + post.id;
const src = $('抽圖片URL').first().json;
let uploaded = 0;
try { uploaded = $('收集照片ID').first().json.uploadedPhotos || 0; } catch (e) {}

const properties = {
  '粉專貼文連結': { url: permalink },
  '狀態': { select: { name: '已發布' } },
  'KEIS同步': { select: { name: '未同步' } }
};
if (src.generated) {
  properties['粉專文案'] = { rich_text: [{ text: { content: String(src['粉專文案']) } }] };
  properties['社團文案'] = { rich_text: [{ text: { content: String(src['社團文案']) } }] };
  properties['文案版本'] = { number: src.newVersion };
}

return [{ json: {
  notionPageId: src.notionPageId,
  notionBody: { properties },
  permalink,
  社團文案: src['社團文案'],
  caseId: src.caseId,
  replyToken: src.replyToken,
  uploadedPhotos: uploaded
}}];

const d = $('組 Notion PATCH body').first().json;
const photoNote = d.uploadedPhotos > 0
  ? `（含 ${d.uploadedPhotos} 張照片）`
  : '（⚠️ 沒抓到照片，這篇是純文字，需要照片請到 FB 手動補）';
const replyText = `✅ ${d.caseId} 已發布粉專${photoNote}
${d.permalink}

━━━ 社團版文案 ━━━
${d['社團文案']}

撒網社團：直接按上面貼文的「分享」
重點社團：複製社團版文案貼原生文，發了回我「發到 X 社團」`;
return [{ json: { replyToken: d.replyToken, replyText } }];
